import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
	type: 'n8n-nodes-base.manualTrigger',
	version: 1,
	config: { name: 'Manual Trigger' },
});

const denyTest = node({
	type: 'n8n-nodes-base.set',
	version: 3.4,
	config: {
		name: 'deny test',
		parameters: {
			mode: 'manual',
			assignments: {
				assignments: [
					{
						id: 'result',
						name: 'result',
						value: 'deny test node ran',
						type: 'string',
					},
				],
			},
		},
	},
});

export default workflow('deny-test-workflow', 'Deny Test Workflow')
	.add(manualTrigger)
	.to(denyTest);

